'use client';

import { useEffect } from 'react';
import { useTheme } from 'next-themes';
import { useSiteSettings } from '@/hooks/useSiteSettings';

export function ThemeManager() {
  const { settings, isLoading } = useSiteSettings();
  const { setTheme } = useTheme();

  useEffect(() => {
    if (isLoading) return;

    const applyTheme = () => {
      if (settings.theme.autoSwitchByTime) {
        const now = new Date();
        const currentTime = now.getHours() * 60 + now.getMinutes();
        
        const [startHour, startMin] = settings.theme.darkModeStart.split(':').map(Number);
        const [endHour, endMin] = settings.theme.darkModeEnd.split(':').map(Number);
        
        const startTime = startHour * 60 + startMin;
        const endTime = endHour * 60 + endMin;
        
        let shouldBeDark = false;
        
        if (startTime > endTime) {
          // Crosses midnight (e.g., 18:00 to 06:00)
          shouldBeDark = currentTime >= startTime || currentTime < endTime;
        } else {
          // Same day (e.g., 09:00 to 17:00)
          shouldBeDark = currentTime >= startTime && currentTime < endTime;
        }
        
        setTheme(shouldBeDark ? 'dark' : 'light');
      } else {
        // Apply default theme
        if (settings.theme.defaultTheme === 'dark') {
          setTheme('dark');
        } else if (settings.theme.defaultTheme === 'light') {
          setTheme('light');
        } else {
          // System theme
          setTheme('system');
        }
      }
    };

    // Apply theme immediately
    applyTheme();

    // Set up interval for auto-switching
    let interval: NodeJS.Timeout | null = null;
    if (settings.theme.autoSwitchByTime) {
      interval = setInterval(applyTheme, 60000); // Check every minute
    }

    return () => {
      if (interval) {
        clearInterval(interval);
      }
    };
  }, [settings.theme, isLoading, setTheme]);

  // This component doesn't render anything
  return null;
}